package main

import (
	"fmt"
	"os"

	"k8s.io/kube-state-metrics/v2/pkg/options"
	yaml "sigs.k8s.io/yaml/goyaml.v3"
)

func main() {
	cases := []struct {
		name string
		data string
		want string
	}{
		{
			name: "legacy custom_resource_config_file key",
			data: "custom_resource_config_file: custom-resource-config.yaml\n",
			want: "custom-resource-config.yaml",
		},
		{
			name: "canonical custom_resource_state_config_file key",
			data: "custom_resource_state_config_file: state-config.yaml\n",
			want: "state-config.yaml",
		},
	}

	for _, tc := range cases {
		opts := options.NewOptions()
		if err := yaml.Unmarshal([]byte(tc.data), opts); err != nil {
			fmt.Fprintf(os.Stderr, "%s: unmarshal failed: %v\n", tc.name, err)
			os.Exit(1)
		}
		if opts.CustomResourceConfigFile != tc.want {
			fmt.Fprintf(os.Stderr, "%s: CustomResourceConfigFile=%q, want %q\n", tc.name, opts.CustomResourceConfigFile, tc.want)
			os.Exit(1)
		}
	}
	fmt.Println("custom resource config file YAML keys map correctly")
}
EOF
