+// UnmarshalYAML decodes Options from config files while preserving legacy option names.
+func (o *Options) UnmarshalYAML(value *yaml.Node) error {
+       type plain Options
+
+       decoded := plain(*o)
+       if err := value.Decode(&decoded); err != nil {
+               return err
+       }
+
+       canonicalCustomResourceConfigFileSet := false
+       legacyCustomResourceConfigFileSet := false
+       legacyCustomResourceConfigFile := ""
+       for i := 0; i+1 < len(value.Content); i += 2 {
+               switch value.Content[i].Value {
+               case "custom_resource_state_config_file":
