+               case "custom_resource_config_file":
+                       legacyCustomResourceConfigFileSet = true
+                       if err := value.Content[i+1].Decode(&legacyCustomResourceConfigFile); err != nil {
+                               return err
+                       }
+               }
+       }
+
+       *o = Options(decoded)
+       if legacyCustomResourceConfigFileSet && !canonicalCustomResourceConfigFileSet {
+               o.CustomResourceConfigFile = legacyCustomResourceConfigFile
+       }
+
+       return nil
